import{_ as n,o as r,c as t,ag as i}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Verträge","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/contracts.md","filePath":"de/features/contracts.md"}'),a={name:"de/features/contracts.md"};function s(l,e,g,u,o,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="vertrage" tabindex="-1">Verträge <a class="header-anchor" href="#vertrage" aria-label="Permalink to &quot;Verträge&quot;">​</a></h1><p>Verwalten Sie wiederkehrende Dienstleistungsvereinbarungen und Mietverträge mit automatischen Abrechnungsplänen.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Verträge repräsentieren laufende Vereinbarungen mit Kunden — wie monatliche Dienstleistungsverträge, Mietvereinbarungen oder Wartungspläne. Sie können automatisch Rechnungen nach einem festgelegten Zeitplan generieren.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Das Vertragsmodul ist optional. Aktivieren Sie es unter <strong>Unternehmen &gt; Funktionen</strong>, wenn Sie es nicht in der Navigation sehen.</p></div><h2 id="vertrag-erstellen" tabindex="-1">Vertrag erstellen <a class="header-anchor" href="#vertrag-erstellen" aria-label="Permalink to &quot;Vertrag erstellen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Verträge &gt; Neuer Vertrag</strong></li><li>Füllen Sie aus: <ul><li><strong>Name</strong> — Ein aussagekräftiger Titel (z. B. „Monatlicher Reinigungsservice&quot;)</li><li><strong>Kunde</strong> — Die Vertragspartei</li><li><strong>Betrag</strong> — Der wiederkehrende Abrechnungsbetrag</li><li><strong>Wiederholung</strong> — Wie oft abgerechnet wird (wöchentlich, monatlich, vierteljährlich, jährlich)</li><li><strong>Startdatum</strong> — Wann der Vertrag beginnt</li><li><strong>Enddatum</strong> — Optionales Enddatum</li><li><strong>Beschreibung</strong> — Bedingungen und Details</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><h2 id="vertragsstatus" tabindex="-1">Vertragsstatus <a class="header-anchor" href="#vertragsstatus" aria-label="Permalink to &quot;Vertragsstatus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Aktiv</strong></td><td>Derzeit in Kraft, generiert Rechnungen</td></tr><tr><td><strong>Inaktiv</strong></td><td>Pausiert — keine Rechnungen werden generiert</td></tr></tbody></table><h2 id="automatische-rechnungsstellung" tabindex="-1">Automatische Rechnungsstellung <a class="header-anchor" href="#automatische-rechnungsstellung" aria-label="Permalink to &quot;Automatische Rechnungsstellung&quot;">​</a></h2><p>Aktive Verträge mit einem Wiederholungsplan generieren automatisch Rechnungen in jedem Abrechnungszeitraum. Das System:</p><ol><li>Erstellt einen Rechnungsentwurf basierend auf den Vertragsbedingungen</li><li>Wendet den richtigen Kunden, Betrag und die Beschreibung an</li><li>Folgt Ihren Rechnungsnummerierungseinstellungen</li></ol><p>Sie können generierte Rechnungen manuell überprüfen und versenden oder den automatischen Versand konfigurieren.</p><h2 id="verknupfung-mit-vermogenswerten" tabindex="-1">Verknüpfung mit Vermögenswerten <a class="header-anchor" href="#verknupfung-mit-vermogenswerten" aria-label="Permalink to &quot;Verknüpfung mit Vermögenswerten&quot;">​</a></h2><p>Verträge können mit <a href="/de/features/objects">Objekten/Vermögenswerten</a> für die Mietverwaltung verknüpft werden:</p><ul><li>Verknüpfen Sie einen Vertrag mit einer Immobilie, einem Fahrzeug oder einem Gerät</li><li>Verfolgen Sie, welche Vermögenswerte derzeit vermietet sind und an wen</li><li>Sehen Sie den Vertragsverlauf pro Vermögenswert</li></ul><h2 id="kennzahlen" tabindex="-1">Kennzahlen <a class="header-anchor" href="#kennzahlen" aria-label="Permalink to &quot;Kennzahlen&quot;">​</a></h2><p>Die Vertragsliste zeigt zusammenfassende Kennzahlen:</p><ul><li>Gesamtzahl aktiver Verträge</li><li>Gesamtvertragswert</li><li>Verträge nach Wiederholungsart</li></ul><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><ul><li><strong>Status ändern</strong> — Mehrere Verträge aktivieren oder deaktivieren</li><li><strong>Archivieren</strong> — Ins Archiv verschieben</li><li><strong>Wiederherstellen</strong> — Archivierte Verträge zurückholen</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Verwenden Sie Verträge zusammen mit <a href="/de/features/recurring-invoices">wiederkehrenden Rechnungen</a> für verschiedene Abrechnungsszenarien</li><li>Verknüpfen Sie Verträge mit Objekten für eine vollständige Mietverwaltung</li><li>Setzen Sie Enddaten, um vor Vertragsablauf benachrichtigt zu werden</li><li>Verwenden Sie den Vertragsfilter, um aktive und inaktive Verträge auf einen Blick zu sehen</li></ul>',23)])])}const m=n(a,[["render",s]]);export{c as __pageData,m as default};
